+    // Create result object
+    const obj = qjs.JS_NewObject(ctx);
+
+    // Set exitCode
+    _ = qjs.JS_SetPropertyStr(ctx, obj, "exitCode", qjs.JS_NewInt32(ctx, result.exit_code));
